const QUESTIONS_CISSP_C3 = [
  { id:30501, domain:6, level:2, question:"What is the primary objective of a red team exercise?", options:["A Testing backup and recovery procedures under realistic conditions","B Reviewing security policies for completeness and accuracy","C Simulating real adversary tactics to identify gaps in detection and response capabilities","D Training blue team analysts on new threat detection tools"], correct:2, explanation:"Red team exercises simulate advanced adversary tactics, techniques, and procedures (TTPs) to test whether the organization can detect, respond to, and contain realistic attack scenarios that may evade standard controls." },
  { id:30502, domain:6, level:2, question:"What is the purpose of a purple team exercise?", options:["A Combining red and blue teams to improve both offensive and defensive capabilities collaboratively","B Testing physical security controls alongside cyber defenses","C Evaluating third-party vendor security with the internal team","D Training entry-level security analysts with guided scenarios"], correct:0, explanation:"Purple team exercises combine red team attack techniques with blue team defensive analysis in real-time, allowing both teams to learn from each other—attackers adjust TTPs, defenders improve detection rules and response." },
  { id:30503, domain:6, level:2, question:"What does 'security control testing' verify?", options:["A That security policies are documented and approved","B That security staff understand their responsibilities","C That implemented controls function as intended and meet their stated objectives","D That vendors meet contractual security obligations"], correct:2, explanation:"Security control testing validates that implemented controls (technical, administrative, physical) actually work as designed, providing assurance that the security investment is delivering the intended risk reduction." },
  { id:30504, domain:6, level:2, question:"What is the key benefit of continuous security monitoring over periodic assessments?", options:["A It provides real-time visibility into security posture, detecting changes and threats as they occur","B It satisfies all compliance requirements without additional audits","C It reduces the cost of security operations over time","D It eliminates the need for annual penetration tests"], correct:0, explanation:"Continuous monitoring provides ongoing visibility into the security state—detecting configuration drift, new vulnerabilities, and active threats in near-real-time rather than at point-in-time snapshots that can miss interval activity." },
  { id:30505, domain:6, level:2, question:"What is interactive application security testing (IAST)?", options:["A Testing that instruments the running application to analyze behavior during test execution","B Manual code review by security experts during development","C Automated testing of all application APIs for security vulnerabilities","D Testing the application's security configuration against a compliance baseline"], correct:0, explanation:"IAST instruments applications with agents/sensors that observe behavior during testing, combining SAST code analysis visibility with DAST runtime accuracy, identifying vulnerabilities with their exact code locations." },
  { id:30506, domain:6, level:2, question:"What does a compliance audit specifically evaluate?", options:["A The effectiveness of technical security controls","B The organization's overall risk management program","C Whether an organization meets the requirements of a specific standard or regulation","D The security maturity level compared to industry peers"], correct:2, explanation:"Compliance audits measure adherence to specific regulatory, legal, or contractual requirements (HIPAA, PCI-DSS, SOX), determining whether the organization meets mandated standards rather than evaluating overall security effectiveness." },
  { id:30507, domain:6, level:2, question:"What is the purpose of an audit trail (audit log)?", options:["A Monitoring system performance to prevent failures","B Automating security policy enforcement","C Providing a chronological record of user activities for accountability and investigation","D Encrypting sensitive data in databases"], correct:2, explanation:"Audit trails record user and system activities chronologically, providing accountability, supporting forensic investigations, detecting unauthorized actions, and demonstrating compliance with security policies." },
  { id:30508, domain:6, level:2, question:"What vulnerability does cross-site request forgery (CSRF) exploit?", options:["A The browser's same-origin policy implementation","B Server-side input validation of web form data","C The trust that an application has in an authenticated user's browser","D The HTTP session management implementation"], correct:2, explanation:"CSRF exploits the trust a web application has in a user's authenticated browser by tricking the browser into making unintended requests using the user's existing session, performing actions without the user's knowledge." },
  { id:30509, domain:6, level:2, question:"What is SQL injection and how does it affect database security?", options:["A Injecting malicious code into database backups to compromise data integrity","B Inserting malicious SQL statements into input fields to manipulate database queries","C Exploiting weak database passwords to gain unauthorized access","D Using database replication to copy sensitive data to an attacker's system"], correct:1, explanation:"SQL injection inserts malicious SQL code into input fields that gets executed by the database, potentially exposing, modifying, or deleting data, bypassing authentication, and in some cases achieving code execution on the server." },
  { id:30510, domain:6, level:2, question:"What is directory traversal (path traversal) vulnerability?", options:["A Navigating outside intended directory boundaries to access restricted files using ../ sequences","B Listing active directory users without authorization","C Exploiting misconfigured directory service permissions","D Using symbolic links to redirect file access to sensitive locations"], correct:0, explanation:"Directory traversal exploits insufficient input validation to navigate outside the intended directory using ../ sequences, allowing attackers to read files outside the web root (like /etc/passwd or configuration files with credentials)." },
  { id:30511, domain:6, level:2, question:"What is the purpose of security metrics?", options:["A Demonstrating regulatory compliance to auditors","B Measuring the effectiveness and efficiency of security controls and programs over time","C Tracking the number of security incidents for reporting","D Calculating the return on investment of security tools"], correct:1, explanation:"Security metrics quantify security program performance, effectiveness of controls, and risk trends, enabling data-driven decisions, demonstrating value to leadership, and identifying areas requiring improvement." },
  { id:30512, domain:6, level:2, question:"What does code review in security assess?", options:["A Source code for security vulnerabilities, logic flaws, and insecure coding practices","B Compliance of code with organizational software development policies","C Application performance under load testing conditions","D Version control practices for tracking code changes"], correct:0, explanation:"Security code review examines source code to identify vulnerabilities like injection flaws, authentication weaknesses, insecure cryptography, and logic errors that could be exploited, typically performed by security-aware developers or specialists." },
  { id:30513, domain:6, level:2, question:"What is the CIS Benchmarks' primary purpose?", options:["A Certifying security professionals through examination","B Providing legal frameworks for cybersecurity regulations","C Ranking organizations by cybersecurity maturity level","D Offering community-developed secure configuration guidelines for systems and software"], correct:3, explanation:"CIS Benchmarks are consensus-based, community-developed configuration guidelines providing specific, prescriptive security recommendations for securely configuring operating systems, applications, and cloud environments." },
  { id:30514, domain:6, level:2, question:"What distinguishes a zero-day vulnerability?", options:["A A vulnerability that has been public for zero days before being patched","B A vulnerability affecting zero percent of systems in production","C A vulnerability unknown to the vendor with no available patch","D A vulnerability requiring zero technical skill to exploit"], correct:2, explanation:"Zero-day vulnerabilities are unknown to the affected vendor (or known but unpatched), meaning there is no available fix, leaving defenders unable to apply patches and relying on other detection and mitigation controls." },
  { id:30515, domain:6, level:2, question:"What is the purpose of a security scorecard?", options:["A Providing a consolidated view of key security metrics and risk indicators for leadership","B Assigning grades to security staff performance annually","C Scoring the severity of individual security vulnerabilities","D Ranking security vendors by product effectiveness"], correct:0, explanation:"Security scorecards aggregate key performance indicators (KPIs) and key risk indicators (KRIs) into a dashboard for executive and management consumption, enabling data-driven decisions and board-level security governance." },
  { id:30516, domain:7, level:2, question:"What is the purpose of a security information and event management (SIEM) correlation rule?", options:["A Encrypting log data before long-term archival","B Automatically remediating detected threats without analyst review","C Filtering logs to reduce storage costs","D Detecting patterns across multiple log sources that indicate a security incident"], correct:3, explanation:"SIEM correlation rules analyze sequences and combinations of events across multiple sources to identify attack patterns (failed logins + successful login from new location, or malware hash + outbound connection) that automated alerting alone would miss." },
  { id:30517, domain:7, level:2, question:"What is the primary security concern with social engineering attacks?", options:["A They are detectable by standard intrusion detection systems","B They require sophisticated technical skills to execute","C They only target senior executives and privileged users","D They exploit human psychology to bypass technical security controls"], correct:3, explanation:"Social engineering manipulates people rather than technology, exploiting trust, urgency, authority, and other psychological principles to bypass technical controls. Even technically strong environments are vulnerable to well-crafted social engineering." },
  { id:30518, domain:7, level:2, question:"What is phishing and how does spear phishing differ from generic phishing?", options:["A Phishing uses email; spear phishing uses telephone calls","B Phishing is an automated attack; spear phishing requires manual effort","C Spear phishing steals credentials; phishing deploys malware","D Phishing targets many people indiscriminately; spear phishing targets specific individuals with tailored messages"], correct:3, explanation:"Generic phishing sends mass emails with generic lures. Spear phishing targets specific individuals or organizations with highly personalized content derived from research (LinkedIn, public data), significantly increasing believability and success rate." },
  { id:30519, domain:7, level:2, question:"What is vishing in the context of social engineering?", options:["A A phishing attack using fake video calls","B A variant of phishing targeting VoIP infrastructure","C A social engineering attack conducted via voice calls (telephone)","D An attack using voicemail as the initial contact vector"], correct:2, explanation:"Vishing (voice phishing) uses phone calls to trick victims into revealing sensitive information or performing actions (wiring money, providing MFA codes), often impersonating banks, IT support, or government agencies." },
  { id:30520, domain:7, level:2, question:"What is whaling in social engineering?", options:["A Spear phishing attacks specifically targeting high-profile executives or senior leadership","B Large-scale phishing campaigns targeting thousands of users","C Advanced persistent threat campaigns targeting critical infrastructure","D Multi-stage attacks combining phishing with malware deployment"], correct:0, explanation:"Whaling is a spear phishing variant targeting 'big fish'—C-level executives, board members, or other high-value individuals—using highly crafted messages relevant to their roles (board meeting invitations, SEC filings, legal notices)." },
  { id:30521, domain:7, level:2, question:"What is the primary purpose of security awareness training?", options:["A Educating users to recognize and respond appropriately to security threats","B Training users on the operation of security tools and systems","C Ensuring staff can pass security certification examinations","D Teaching technical security skills to all employees"], correct:0, explanation:"Security awareness training educates users about common threats (phishing, social engineering, malware), safe behaviors, and security policies, turning the human element from a vulnerability into a security asset." },
  { id:30522, domain:7, level:2, question:"What is an advanced persistent threat (APT)?", options:["A A highly destructive malware variant that spreads rapidly through networks","B An automated attack framework that adapts to defensive measures","C A sophisticated, long-term targeted attack typically by nation-state or well-resourced threat actors","D A type of ransomware with advanced encryption capabilities"], correct:2, explanation:"APTs are sophisticated, stealthy, long-duration attacks typically conducted by nation-states or organized criminal groups against specific high-value targets, using advanced TTPs and maintaining persistent access over extended periods." },
  { id:30523, domain:7, level:2, question:"What is the Cyber Kill Chain model used for?", options:["A Measuring the cost of each phase of a cyberattack","B Describing the stages of a cyberattack to guide detection and response strategies","C Assigning severity scores to different types of cyberattacks","D Documenting the legal chain of evidence in cybercrime prosecution"], correct:1, explanation:"Lockheed Martin's Cyber Kill Chain describes seven stages of an attack (reconnaissance, weaponization, delivery, exploitation, installation, C2, actions on objectives), helping defenders identify opportunities to detect and stop attacks early." },
  { id:30524, domain:7, level:2, question:"What is the primary security concern with legacy systems?", options:["A Legacy systems consume more computing resources than modern systems","B Legacy systems may run unsupported software with unpatched vulnerabilities","C Legacy systems are incompatible with modern identity management solutions","D Legacy systems generate excessive log data that overwhelms SIEM systems"], correct:1, explanation:"Legacy systems often run operating systems or software that vendors no longer support, meaning security vulnerabilities are discovered but patches are never released, leaving organizations permanently exposed to known exploits." },
  { id:30525, domain:7, level:2, question:"What is a security baseline deviation?", options:["A A change in security policy approved by management","B A configuration change that moves a system outside its established secure baseline","C A vulnerability that exceeds the organization's risk tolerance threshold","D A security alert generated when baseline monitoring detects unusual activity"], correct:1, explanation:"Baseline deviation occurs when a system's configuration drifts from its approved secure baseline—through unauthorized changes, misconfiguration, or system updates—potentially introducing vulnerabilities or weakening security controls." },
  { id:30526, domain:7, level:2, question:"What does 'hardening' a system involve?", options:["A Increasing a system's processing capacity for security applications","B Installing all available vendor patches immediately after release","C Applying physical security measures to protect server hardware","D Reducing the attack surface by disabling unnecessary services, accounts, and features"], correct:3, explanation:"System hardening reduces the attack surface by disabling unnecessary services, removing default accounts, closing unused ports, applying CIS benchmarks, and enabling appropriate security features, minimizing potential entry points." },
  { id:30527, domain:7, level:2, question:"What is an endpoint detection and response (EDR) tool's primary capability?", options:["A Blocking all unauthorized network connections at the host level","B Encrypting all data stored on endpoints automatically","C Providing visibility into endpoint activity and enabling investigation and response to threats","D Managing patch deployment across all enterprise endpoints"], correct:2, explanation:"EDR tools continuously monitor endpoint activity, record telemetry (processes, network connections, file operations), detect suspicious behavior, and enable analysts to investigate and respond to threats on individual hosts." },
  { id:30528, domain:7, level:2, question:"What is change management's security role?", options:["A Automating software deployment to reduce human error","B Controlling procurement of security tools and services","C Ensuring changes are reviewed, tested, and approved to prevent unauthorized or disruptive modifications","D Managing organizational restructuring during security incidents"], correct:2, explanation:"Change management ensures all changes to systems go through review (security impact assessment), approval, testing, and documentation, preventing unauthorized changes and ensuring changes don't introduce new vulnerabilities." },
  { id:30529, domain:7, level:2, question:"What is the purpose of security event triage?", options:["A Reporting security event statistics to executive leadership","B Automatically blocking all suspicious events without analyst review","C Archiving security events for long-term forensic preservation","D Prioritizing security events based on severity and impact to focus analyst attention"], correct:3, explanation:"Event triage assesses incoming alerts to determine which require immediate action, separating high-fidelity alerts from noise, filtering false positives, and ensuring analysts focus limited resources on the most critical events first." },
  { id:30530, domain:7, level:2, question:"What is the primary benefit of threat intelligence sharing between organizations?", options:["A Providing earlier warning of emerging threats based on observations across multiple environments","B Reducing the cost of individual security operations","C Eliminating the need for in-house threat analysis capabilities","D Meeting regulatory requirements for information sharing"], correct:0, explanation:"Threat intelligence sharing allows organizations to benefit from each other's observations—IOCs, TTPs, attack campaigns—providing earlier warning of threats targeting similar industries and reducing collective defender disadvantage." },
  { id:30531, domain:7, level:2, question:"What is a security information sharing platform like ISAC?", options:["A A government-mandated platform for reporting security incidents","B A community of sector-specific organizations sharing threat intelligence and best practices","C A commercial product providing threat intelligence feeds","D A regulatory compliance reporting portal for the financial sector"], correct:1, explanation:"Information Sharing and Analysis Centers (ISACs) are sector-specific organizations (financial, healthcare, energy) where members share threat intelligence, vulnerabilities, and best practices to improve collective security posture." },
  { id:30532, domain:7, level:2, question:"What is sandbox analysis used for in malware investigation?", options:["A Executing suspicious files in an isolated environment to observe behavior without risking production systems","B Testing new security tools in isolated environments before production deployment","C Isolating compromised systems from the network during incident response","D Creating isolated test environments for penetration testing exercises"], correct:0, explanation:"Malware sandboxes execute suspicious files in isolated virtual environments, capturing behavior (network connections, file modifications, registry changes, process creation) to determine if files are malicious without risking real systems." },
  { id:30533, domain:7, level:2, question:"What does 'lateral movement' mean in the context of a cyberattack?", options:["A An attacker moving from one organization to a connected partner organization","B An attacker moving through a compromised network to access additional systems","C Traffic moving between different network segments through a firewall","D An IDS alert escalating from low to high severity over time"], correct:1, explanation:"Lateral movement describes techniques attackers use to progressively access more systems and data within a compromised network after initial entry—using stolen credentials, exploiting vulnerabilities, or leveraging trusted connections between systems." },
  { id:30534, domain:7, level:2, question:"What is command and control (C2) infrastructure used for in an attack?", options:["A Managing security operations center workflows","B Enabling attackers to send instructions to and receive data from compromised systems","C Coordinating multi-team incident response activities","D Providing real-time threat intelligence to security tools"], correct:1, explanation:"C2 infrastructure allows attackers to remotely control compromised systems (bots/implants), issue commands, receive stolen data, deploy additional tools, and maintain persistent access, often disguising traffic as legitimate HTTPS or DNS." },
  { id:30535, domain:7, level:2, question:"What is the security concern with DNS tunneling?", options:["A DNS requests can overwhelm DNS servers with excessive query volume","B DNS amplification attacks use tunneling to increase attack bandwidth","C Attackers use DNS queries to covertly exfiltrate data or establish C2 channels bypassing firewalls","D DNS tunneling exposes internal network topology to external observers"], correct:2, explanation:"DNS tunneling encodes data in DNS queries/responses to exfiltrate information or establish covert C2 channels, exploiting the fact that DNS is often allowed through firewalls even when other protocols are blocked." },
  { id:30536, domain:7, level:2, question:"What is living off the land (LotL) in attack techniques?", options:["A Attackers using physical access to compromise systems","B Attackers maintaining persistent access without deploying any additional tools","C Using legitimate system tools (PowerShell, WMI, certutil) to conduct attacks without custom malware","D Using compromised cloud services as attack infrastructure"], correct:2, explanation:"LotL techniques use tools already present on the system (built-in OS utilities like PowerShell, certutil, wmic) to perform malicious actions, making detection harder since these tools are legitimate and commonly used." },
  { id:30537, domain:7, level:2, question:"What is the primary purpose of data classification in security operations?", options:["A Organizing data alphabetically for efficient retrieval","B Reducing storage costs by organizing data by importance","C Meeting regulatory requirements for data labeling","D Identifying the sensitivity level of data to apply appropriate security controls"], correct:3, explanation:"Data classification identifies the sensitivity level of information, enabling appropriate security controls to be applied—ensuring highly sensitive data receives stronger protections (encryption, access controls, monitoring) than less sensitive data." },
  { id:30538, domain:7, level:2, question:"What is the role of deception technology in security operations?", options:["A Training security analysts using simulated attack scenarios","B Using honeypots as offensive tools against attackers","C Deceiving attackers about a system's true vulnerabilities","D Deploying decoys and traps to detect attackers and slow their progress through the network"], correct:3, explanation:"Deception technology deploys decoys (fake credentials, honeypot systems, breadcrumbs) that attract attackers and alert defenders when touched, providing early warning of lateral movement with virtually zero false positives." },
  { id:30539, domain:7, level:2, question:"What is the purpose of a security orchestration platform?", options:["A Composing music for security training videos","B Automating and coordinating security operations workflows across multiple tools","C Managing cryptographic key orchestration across enterprise systems","D Coordinating penetration testing engagements across multiple teams"], correct:1, explanation:"Security orchestration integrates disparate security tools through automated workflows, enabling coordinated responses (phishing investigation: extract IOCs → enrich → block → remediate) without manual handoffs between tools." },
  { id:30540, domain:7, level:2, question:"What is a tabletop exercise specifically designed to test?", options:["A Technical response capabilities using production systems","B Backup and recovery procedures for critical systems","C The effectiveness of technical security controls","D Decision-making, communication, and coordination of stakeholders during a simulated incident"], correct:3, explanation:"Tabletop exercises specifically test whether stakeholders understand their roles, can make sound decisions, communicate effectively, and coordinate actions during an incident, without requiring any technical execution." },
  { id:30541, domain:8, level:2, question:"What is the Software Development Life Cycle (SDLC) and why does security integration matter?", options:["A A project management methodology for IT projects","B A structured process for software development where integrating security at each phase reduces later remediation costs","C A compliance framework for software quality management","D A documentation standard for software architecture and design"], correct:1, explanation:"The SDLC defines phases of software development (requirements, design, coding, testing, deployment, maintenance). Integrating security at each phase (secure SDLC) is significantly cheaper than addressing vulnerabilities after release." },
  { id:30542, domain:8, level:2, question:"What is the primary benefit of DevSecOps?", options:["A Centralizing security responsibilities with developers rather than security teams","B Eliminating the need for dedicated security teams","C Accelerating software release cycles by removing security approval gates","D Integrating security practices and testing throughout the development pipeline automatically"], correct:3, explanation:"DevSecOps integrates security into every stage of the DevOps pipeline—automated security scanning, dependency checks, infrastructure-as-code security—making security a shared responsibility and catching issues before they reach production." },
  { id:30543, domain:8, level:2, question:"What is a security requirement in software development?", options:["A A technical constraint limiting which programming languages can be used","B A performance benchmark the security controls must meet","C A compliance checklist completed before software deployment","D A functional or non-functional specification defining how the system must handle security"], correct:3, explanation:"Security requirements define what the system must do to be secure—authentication requirements, encryption standards, access control specifications, and non-functional requirements like audit logging and session management." },
  { id:30544, domain:8, level:2, question:"What does input validation protect against in web applications?", options:["A Brute force attacks against application login forms","B Unauthorized access to application administrative functions","C Session hijacking through stolen authentication tokens","D Injection attacks by rejecting or sanitizing unexpected, malicious input"], correct:3, explanation:"Input validation rejects or sanitizes unexpected input (special characters, SQL syntax, script tags) before processing, preventing injection attacks (SQL injection, XSS, command injection) that exploit trust in user-supplied data." },
  { id:30545, domain:8, level:2, question:"What is output encoding used for in web application security?", options:["A Formatting output consistently across different client platforms","B Compressing output data for efficient transmission","C Encrypting application output for confidentiality in transit","D Converting special characters to safe representations to prevent XSS when displaying user data"], correct:3, explanation:"Output encoding converts characters like < > & ' \" to HTML entities when rendering user-supplied data in browsers, preventing browsers from interpreting data as executable HTML/JavaScript, thus preventing XSS attacks." },
  { id:30546, domain:8, level:2, question:"What is the concept of secure by default in software design?", options:["A All users start with administrator privileges until access is restricted","B Default settings are optimized for usability rather than security","C Applications ship with the most secure configuration enabled by default","D Security features must be configured separately by IT administrators"], correct:2, explanation:"Secure by default means applications are delivered with the safest configuration enabled out of the box (minimal permissions, no default credentials, required authentication), so insecure configurations require deliberate action to enable." },
  { id:30547, domain:8, level:2, question:"What is the primary risk of using third-party libraries in software development?", options:["A Third-party code may not be compatible with all target platforms","B Third-party licenses may conflict with commercial software policies","C Vulnerabilities in dependencies can be inherited by the application","D Dependencies increase the application's overall size and performance overhead"], correct:2, explanation:"Applications inherit vulnerabilities in their third-party dependencies. A critical CVE in a widely-used library (like Log4Shell in Log4j) can affect thousands of applications, highlighting the need for software composition analysis." },
  { id:30548, domain:8, level:2, question:"What is the purpose of error handling and exception management in secure coding?", options:["A Preventing error messages from revealing system details that could aid attackers","B Automatically recovering from all errors without user notification","C Logging all exceptions to a central database for developer review","D Improving application performance by handling errors gracefully"], correct:0, explanation:"Improper error handling can expose stack traces, database queries, file paths, and version information to attackers. Secure error handling shows generic messages to users while logging details internally for developer review." },
  { id:30549, domain:8, level:2, question:"What is memory-safe programming and why does it matter for security?", options:["A Optimizing memory usage to prevent application crashes","B Encrypting sensitive data stored in application memory","C Using languages or practices that prevent buffer overflows and memory corruption vulnerabilities","D Managing memory allocation to prevent performance degradation"], correct:2, explanation:"Memory-safe programming prevents vulnerabilities like buffer overflows, use-after-free, and format string bugs that arise from improper memory management, often exploitable for arbitrary code execution. Rust and Go provide memory safety guarantees." },
  { id:30550, domain:8, level:2, question:"What is security testing in the CI/CD pipeline?", options:["A Automatically executing security scans at each stage of continuous integration and deployment","B Testing the security of the CI/CD infrastructure itself","C Running security tools manually before each major release","D Reviewing security requirements with the product team during sprint planning"], correct:0, explanation:"Security testing in CI/CD automatically runs SAST, dependency scanning, container scanning, and configuration checks at each commit/build, providing immediate feedback to developers and preventing vulnerable code from progressing through the pipeline." },
  { id:30551, domain:8, level:2, question:"What is a software bill of materials (SBOM)?", options:["A A project cost estimate for software development","B A security compliance report for enterprise software","C A comprehensive inventory of all components and dependencies in a software product","D A changelog documenting all software version updates"], correct:2, explanation:"An SBOM lists all components, libraries, and dependencies in a software product with their versions and licenses, enabling organizations to quickly identify affected software when vulnerabilities are disclosed in specific components." },
  { id:30552, domain:8, level:2, question:"What is the principle of separation of environments in software development?", options:["A Developers and security teams work independently without collaboration","B Different programming languages are used for different application components","C Development, testing, and production environments are isolated to prevent changes from causing unintended production impact","D Source code access is limited to developers with security clearances"], correct:2, explanation:"Separating development, staging, and production environments ensures that untested code, test data, and development tools cannot accidentally impact production, and that production data isn't exposed in less secure development environments." },
  { id:30553, domain:8, level:2, question:"What is the primary purpose of code repositories in secure development?", options:["A Version control and collaboration while maintaining code integrity and change history","B Providing backup storage for compiled application binaries","C Encrypting source code to protect intellectual property","D Automatically deploying code changes to production servers"], correct:0, explanation:"Code repositories (Git, SVN) provide version control, change history, branching for features and fixes, code review workflows, and audit trails of all changes, enabling rollback and supporting secure code review practices." },
  { id:30554, domain:8, level:2, question:"What is the purpose of a web application firewall in relation to OWASP vulnerabilities?", options:["A Encrypting all web traffic between clients and servers","B Providing virtual patching against known web application vulnerabilities while source code fixes are developed","C Replacing secure coding practices with external controls","D Testing web applications automatically for OWASP Top 10 vulnerabilities"], correct:1, explanation:"WAFs can provide virtual patching—blocking exploitation attempts against known vulnerabilities without modifying the underlying code—buying time for developers to implement proper fixes while protecting exposed applications." },
  { id:30555, domain:8, level:2, question:"What is an API security concern specific to REST APIs?", options:["A REST APIs are inherently insecure due to their stateless nature","B REST APIs are only vulnerable to denial-of-service attacks","C REST APIs cannot implement transport-layer encryption","D Broken object level authorization allows API callers to access other users' resources"], correct:3, explanation:"Broken Object Level Authorization (BOLA/IDOR) is the #1 API vulnerability—APIs that don't verify whether the requesting user is authorized to access the specific object they're requesting, allowing horizontal privilege escalation." },
  { id:30556, domain:8, level:2, question:"What is the concept of 'shifting security left' in software development?", options:["A Assigning security responsibilities to developers rather than security teams","B Prioritizing security over feature development in sprint planning","C Moving security controls from application code to infrastructure","D Integrating security testing and practices earlier in the development lifecycle"], correct:3, explanation:"Shifting security left means integrating security testing, threat modeling, and security requirements earlier in the SDLC (design and coding phases), when fixing issues is cheaper and faster than addressing them in production." },
  { id:30557, domain:8, level:2, question:"What is privilege escalation in software security?", options:["A Gaining more access than authorized, either horizontally (other users) or vertically (higher privileges)","B An authorized process for users to request elevated permissions","C The process of granting temporary elevated access for administrative tasks","D Escalating security incidents to management based on severity levels"], correct:0, explanation:"Privilege escalation exploits vulnerabilities to gain higher access than authorized: vertical escalation gains admin/root from regular user privileges; horizontal escalation accesses another user's data at the same privilege level." },
  { id:30558, domain:8, level:2, question:"What is the purpose of a software security assessment (application security assessment)?", options:["A Evaluating the performance and scalability of production applications","B Identifying security vulnerabilities in applications through various testing and review techniques","C Assessing compliance of development teams with coding standards","D Reviewing the licensing and intellectual property of application components"], correct:1, explanation:"Application security assessments use combinations of SAST, DAST, IAST, penetration testing, and code review to identify vulnerabilities in applications before or after deployment, providing remediation guidance." },
  { id:30559, domain:8, level:2, question:"What is the security risk of hard-coded credentials in application code?", options:["A Hard-coded credentials are easier to steal in a data breach","B Credentials embedded in code cannot be changed without a code update, and may be exposed in source repositories","C Hard-coded credentials violate password complexity requirements","D Hard-coded credentials prevent rotation, increasing risk over time, though they are never visible in code repositories"], correct:1, explanation:"Hard-coded credentials in source code are a critical risk: they can be exposed in public repositories, binaries, or disassembly; they cannot be easily rotated; and they often have broad access since they were intended for development use." },
  { id:30560, domain:8, level:2, question:"What is container image hardening?", options:["A Minimizing the container's attack surface by removing unnecessary components, running as non-root, and using minimal base images","B Encrypting container images to prevent unauthorized execution","C Restricting container registry access to authorized development teams","D Scanning containers for malware before deployment to production"], correct:0, explanation:"Container hardening reduces attack surface by using minimal base images (distroless), removing unnecessary tools, running processes as non-root, implementing read-only filesystems, and scanning images for CVEs before deployment." },
  { id:30561, domain:8, level:2, question:"What is the purpose of security in software architecture review?", options:["A Ensuring the software meets performance and scalability requirements","B Identifying security weaknesses in design before they become expensive-to-fix implementation vulnerabilities","C Reviewing the software architecture against compliance documentation","D Evaluating vendor architecture for procurement decisions"], correct:1, explanation:"Architecture security review identifies flaws in trust boundaries, data flows, authentication models, and security control placement early in design, preventing entire classes of vulnerabilities that would be expensive to fix after implementation." },
  { id:30562, domain:8, level:2, question:"What is abstraction in object-oriented programming security?", options:["A A technique for hiding the complexity of cryptographic operations","B Creating abstract classes that cannot be instantiated directly","C Hiding implementation details and exposing only necessary interfaces, reducing the attack surface","D Separating security code from application business logic"], correct:2, explanation:"Abstraction hides implementation details behind interfaces, reducing the attack surface by exposing only necessary operations. Callers interact with well-defined interfaces rather than internal structures, limiting unintended access paths." },
  { id:30563, domain:8, level:2, question:"What does server-side request forgery (SSRF) allow an attacker to do?", options:["A Forge server authentication tokens to bypass web application security","B Forge digital signatures on server-generated documents","C Replace legitimate server responses with malicious content","D Cause the server to make requests to internal resources on behalf of the attacker"], correct:3, explanation:"SSRF tricks the server into making HTTP requests to internal resources (metadata APIs, internal services, cloud instance metadata endpoints), potentially exposing internal network access and sensitive configuration data." },
  { id:30564, domain:8, level:2, question:"What is insecure deserialization and why is it dangerous?", options:["A Deserializing untrusted data that can lead to remote code execution or other critical attacks","B Storing serialized objects in unencrypted formats","C Transmitting serialized objects over unencrypted channels","D Using outdated serialization formats that lack modern security features"], correct:0, explanation:"Insecure deserialization occurs when applications deserialize untrusted, attacker-controlled data. Manipulated serialized objects can cause remote code execution, authentication bypass, or privilege escalation during the deserialization process." },
  { id:30565, domain:8, level:2, question:"What is security misconfigurations and why do they commonly occur?", options:["A Intentional security bypasses implemented by developers for testing purposes","B Incorrectly configured security settings due to default credentials, unnecessary features, or missing hardening","C Security tools configured too aggressively, causing false positives","D Incompatibilities between security tools and application configurations"], correct:1, explanation:"Security misconfiguration is the most prevalent web vulnerability, resulting from default credentials, unnecessary features/services enabled, error messages exposing system details, and missing hardening—often due to insufficient configuration management." },
  { id:30566, domain:8, level:2, question:"What is the primary purpose of a web application penetration test?", options:["A Compliance verification for regulatory requirements","B Automated scanning of web applications for known CVEs","C Identifying exploitable vulnerabilities in web applications by simulating real attack techniques","D Performance testing of web applications under attack load"], correct:2, explanation:"Web application penetration tests combine automated tools with manual testing techniques to discover and validate exploitable vulnerabilities, providing concrete evidence of risk and actionable remediation guidance." },
  { id:30567, domain:8, level:2, question:"What does 'security regression' mean in software testing?", options:["A Testing security controls in earlier (regressed) versions of an application","B Reverting to previous security configurations during incidents","C Reducing security requirements due to business pressures","D The reintroduction of previously fixed security vulnerabilities due to code changes"], correct:3, explanation:"Security regression occurs when previously fixed vulnerabilities reappear in new code versions, often due to refactoring, merging of old code branches, or insufficient testing coverage of security-relevant functionality." },
  { id:30568, domain:8, level:2, question:"What is the OWASP Top 10 primarily intended for?", options:["A Providing a scoring system for web application vulnerabilities","B Raising awareness of the most critical web application security risks for developers and organizations","C Certifying web application security professionals","D Listing all known web application vulnerabilities by category"], correct:1, explanation:"The OWASP Top 10 is a consensus awareness document highlighting the most critical web application security risks, intended to help developers, architects, and organizations prioritize security efforts for maximum risk reduction." },
  { id:30569, domain:8, level:2, question:"What is the role of security champions in software development teams?", options:["A Developers trained in security who advocate for security practices within their teams","B Security professionals embedded in development teams to review all code","C Team leads responsible for security compliance reporting","D Security auditors who review sprint deliverables for vulnerabilities"], correct:0, explanation:"Security champions are developers with security training embedded in product teams, promoting security awareness, conducting first-line security reviews, and bridging the gap between dedicated security teams and developers." },
  { id:30570, domain:8, level:2, question:"What is infrastructure as code (IaC) security?", options:["A Encrypting infrastructure configuration scripts for deployment","B Automating compliance reporting for infrastructure configurations","C Using code to replace physical security infrastructure","D Applying security testing and policy enforcement to infrastructure configuration files"], correct:3, explanation:"IaC security applies SAST-like scanning to Terraform, CloudFormation, and similar files, detecting misconfigurations (public S3 buckets, unrestricted security groups) before infrastructure is provisioned, preventing cloud misconfigurations at source." },
  { id:30571, domain:1, level:2, question:"What is the primary purpose of a risk management program?", options:["A Identifying, assessing, and treating risks to an acceptable level aligned with organizational tolerance","B Eliminating all organizational risks through comprehensive controls","C Documenting all security incidents for legal and regulatory purposes","D Providing insurance coverage for losses from security incidents"], correct:0, explanation:"Risk management identifies threats and vulnerabilities, assesses likelihood and impact, and implements appropriate treatments (accept, mitigate, transfer, avoid) to bring residual risk within acceptable tolerance levels." },
  { id:30572, domain:1, level:2, question:"What is risk appetite versus risk tolerance?", options:["A Risk appetite is the amount of risk an organization will pursue; risk tolerance is acceptable deviation from that appetite","B Risk appetite is maximum risk; risk tolerance is minimum acceptable risk","C Risk appetite applies to strategic risks; risk tolerance applies to operational risks","D Risk appetite is qualitative; risk tolerance is always expressed quantitatively"], correct:0, explanation:"Risk appetite is the broad amount and type of risk an organization is willing to accept in pursuit of objectives. Risk tolerance defines acceptable variation around the appetite—the operational boundaries within which risk levels are managed." },
  { id:30573, domain:1, level:2, question:"What is the difference between a threat and a vulnerability?", options:["A A threat is a potential cause of harm; a vulnerability is a weakness that can be exploited by a threat","B Threats are internal; vulnerabilities are external","C Threats are technical; vulnerabilities are administrative","D A threat is a realized attack; a vulnerability is a potential attack vector"], correct:0, explanation:"A threat is any potential danger that could exploit a vulnerability (hackers, malware, natural disasters). A vulnerability is a weakness in a system or process that a threat could exploit. Risk exists at the intersection of threat, vulnerability, and impact." },
  { id:30574, domain:1, level:2, question:"What is the annual loss expectancy (ALE) formula?", options:["A ALE = Total Security Budget ÷ Number of Incidents","B ALE = Asset Value × Threat Probability × Vulnerability Score","C ALE = Single Loss Expectancy × Annual Rate of Occurrence","D ALE = Risk Score × Business Impact Rating"], correct:2, explanation:"ALE = SLE × ARO. Single Loss Expectancy (SLE = Asset Value × Exposure Factor) represents one incident's loss; Annual Rate of Occurrence (ARO) represents frequency per year. ALE quantifies expected annual loss for cost-benefit analysis." },
  { id:30575, domain:1, level:2, question:"What is the primary purpose of a business impact analysis (BIA)?", options:["A Calculating the financial impact of implementing new security controls","B Evaluating the effectiveness of current business continuity plans","C Assessing the security impact of proposed business changes","D Identifying critical business functions and the impact of their disruption to prioritize recovery"], correct:3, explanation:"A BIA identifies which business functions are most critical, quantifies the impact of their disruption (financially, reputationally, operationally), and determines maximum tolerable downtime, driving RTO/RPO requirements." },
  { id:30576, domain:1, level:2, question:"What does due diligence mean in information security?", options:["A Meeting minimum regulatory compliance requirements","B Actively and continuously assessing risks and ensuring appropriate controls are in place","C Completing required security training on time","D Performing security audits on an annual basis"], correct:1, explanation:"Due diligence involves actively investigating, understanding, and appropriately responding to risks—continuously assessing the security posture, researching vendor security, and taking reasonable steps to protect assets based on findings." },
  { id:30577, domain:1, level:2, question:"What is due care in information security?", options:["A Carefully reviewing security policies before implementation","B Conducting security reviews with appropriate professional skepticism","C Being careful when handling sensitive data to prevent accidental disclosure","D Taking reasonable precautions and implementing appropriate safeguards to protect assets"], correct:3, explanation:"Due care means doing what a reasonable person would do under similar circumstances—implementing appropriate security controls, following policies, and taking action to protect organizational assets. It's the standard of reasonable care in practice." },
  { id:30578, domain:1, level:2, question:"What is a security policy's primary function?", options:["A Providing step-by-step technical instructions for security implementations","B Documenting specific security configurations for systems and applications","C Establishing management direction and high-level requirements for information security","D Defining the security tools and technologies approved for use"], correct:2, explanation:"Security policies establish management intent, direction, and high-level requirements—what must be done and why. Standards, procedures, and guidelines provide the how. Policies are technology-neutral and relatively stable over time." },
  { id:30579, domain:1, level:2, question:"What is the difference between a security standard and a security guideline?", options:["A Standards are optional; guidelines are mandatory","B Standards are mandatory requirements; guidelines are recommended practices","C Standards apply to all staff; guidelines apply only to IT teams","D Standards are technical; guidelines are administrative"], correct:1, explanation:"Standards define mandatory requirements (specific configurations, minimum password lengths) that must be followed to comply with policy. Guidelines are optional recommendations and best practices that provide flexibility where appropriate." },
  { id:30580, domain:1, level:2, question:"What is privacy by design?", options:["A Building privacy protections into systems and processes from the design stage","B Implementing privacy controls after system deployment","C Designing systems to comply with specific privacy regulations","D Creating privacy policies that satisfy all applicable legal requirements"], correct:0, explanation:"Privacy by design integrates data protection and privacy principles into the design and architecture of systems from inception, rather than adding them as afterthoughts, ensuring privacy is a fundamental design consideration." },
  { id:30581, domain:1, level:2, question:"What is the purpose of a security governance framework?", options:["A Providing technical controls for managing security risks","B Establishing the structures, processes, and accountability for security decision-making and oversight","C Defining specific security tools approved for organizational use","D Creating security metrics for measuring control effectiveness"], correct:1, explanation:"Security governance frameworks define how security decisions are made, who is accountable, how security aligns with business objectives, and how compliance is monitored, ensuring security is systematically managed at the organizational level." },
  { id:30582, domain:1, level:2, question:"What is personnel security and why does it matter?", options:["A Physical security controls protecting employees from workplace violence","B Security training programs for all organizational staff","C IT security controls protecting employee personal data","D Security measures addressing the insider threat, from hiring through termination"], correct:3, explanation:"Personnel security encompasses background checks, security awareness, separation of duties, mandatory vacation (to detect fraud), and offboarding procedures—addressing the insider threat which is often more dangerous than external threats." },
  { id:30583, domain:1, level:2, question:"What is the concept of 'reasonable expectation of privacy'?", options:["A The amount of privacy guaranteed to employees by organizational policy","B The minimum privacy controls required by applicable regulations","C Whether individuals in a specific context have a legitimate expectation that their information is private","D The privacy protections employees are entitled to under employment law"], correct:2, explanation:"Reasonable expectation of privacy varies by context—people have different expectations in their homes versus public spaces versus workplace systems. Organizations should define and communicate privacy expectations (monitoring policies) to employees." },
  { id:30584, domain:1, level:2, question:"What does the term 'data controller' mean under GDPR?", options:["A Software that manages and processes organizational data","B The regulatory body overseeing data protection compliance","C The technical administrator responsible for database security","D The entity that determines the purposes and means of processing personal data"], correct:3, explanation:"Under GDPR, a data controller is the organization or person who determines why and how personal data is processed. Controllers bear primary responsibility for GDPR compliance and must have a legal basis for processing personal data." },
  { id:30585, domain:1, level:2, question:"What is the primary principle behind data minimization?", options:["A Reducing data storage costs by deleting old records","B Collecting only the minimum personal data necessary for the specified purpose","C Encrypting personal data to minimize privacy risk","D Minimizing the number of people with access to personal data"], correct:1, explanation:"Data minimization (a GDPR principle) requires collecting only the personal data that is adequate, relevant, and necessary for the specific processing purpose, reducing privacy risk and limiting breach impact." },
  { id:30586, domain:1, level:2, question:"What is the role of a Data Protection Officer (DPO)?", options:["A Managing security operations and incident response","B Conducting privacy impact assessments for new projects","C Implementing technical data security controls","D Overseeing GDPR compliance, providing advice, and serving as a contact point for data protection authorities"], correct:3, explanation:"A DPO advises on GDPR obligations, monitors compliance, provides guidance on data protection impact assessments, and acts as a contact point for data subjects and supervisory authorities—required for many public authorities and organizations doing large-scale monitoring." },
  { id:30587, domain:1, level:2, question:"What is a data protection impact assessment (DPIA)?", options:["A An annual review of data protection controls and policies","B A systematic analysis of high-risk data processing activities to identify and mitigate privacy risks","C An audit of personal data held by an organization","D A cost-benefit analysis of implementing data protection technologies"], correct:1, explanation:"DPIAs (required under GDPR for high-risk processing) systematically assess the need, proportionality, and privacy risks of a processing activity before it begins, implementing measures to mitigate identified risks." },
  { id:30588, domain:1, level:2, question:"What is the difference between data at rest and data in transit security?", options:["A Data at rest is stored data requiring encryption/access controls; data in transit is moving data requiring transport encryption","B Data at rest needs stronger encryption; data in transit needs weaker","C Data at rest is more vulnerable than data in transit","D Data at rest refers to archives; data in transit refers to active databases"], correct:0, explanation:"Data at rest (stored on disk, databases, backups) requires encryption and access controls to protect against physical theft or unauthorized access. Data in transit (moving across networks) requires transport-layer encryption (TLS, IPSec) to prevent interception." },
  { id:30589, domain:1, level:2, question:"What is the primary purpose of information classification?", options:["A Organizing information alphabetically for efficient retrieval","B Meeting regulatory requirements for data labeling","C Determining the appropriate level of protection based on sensitivity and business impact","D Reducing storage costs by archiving less important information"], correct:2, explanation:"Information classification identifies data sensitivity and business impact, ensuring appropriate security controls are applied—highly classified data receives stronger protections (encryption, strict access controls) than public information." },
  { id:30590, domain:1, level:2, question:"What is the concept of separation of privileges in security?", options:["A Dividing administrative access among multiple administrators","B Restricting privileged access to specific time windows","C Requiring multiple conditions or approvals before granting access to sensitive functions","D Creating separate accounts for privileged and normal user activities"], correct:2, explanation:"Separation of privileges requires that access to sensitive operations depends on more than one condition (e.g., requiring two keys for a safe, or requiring approval + authentication for privileged actions), preventing single-point compromise." },
  { id:30591, domain:2, level:2, question:"What is data ownership in information security?", options:["A Legal ownership of intellectual property rights to data","B Exclusive access rights to a specific database or data set","C Accountability for classification, protection, and appropriate use of specific data assets","D The department that created a particular set of organizational data"], correct:2, explanation:"Data owners (typically business managers) are accountable for their data assets' classification, determining appropriate handling requirements, approving access requests, and ensuring data is used appropriately per policy." },
  { id:30592, domain:2, level:2, question:"What is data retention and why does it have security implications?", options:["A Keeping data as long as possible to ensure business continuity","B Defining how long data is kept based on legal requirements and business need, with implications for breach scope","C Retaining copies of all data in multiple locations for redundancy","D Keeping metadata about data after the data itself is deleted"], correct:1, explanation:"Data retention policies define how long data is kept and when it's disposed of. Retaining data longer than necessary increases breach scope and compliance risk. Proper disposal (secure deletion, physical destruction) prevents unauthorized recovery." },
  { id:30593, domain:2, level:2, question:"What is the scoping principle in data security?", options:["A Limiting security assessments to specific systems based on compliance requirements","B Defining which data, systems, and boundaries are within the scope of a compliance standard","C Restricting data access to only users within a defined scope of responsibility","D Scoping security controls to be proportional to the value of protected data"], correct:1, explanation:"Scoping defines the boundaries of what is included in a compliance framework (PCI-DSS scope = cardholder data environment). Reducing scope by isolating sensitive data limits the complexity and cost of compliance efforts." },
  { id:30594, domain:2, level:2, question:"What is the primary security concern with cloud data storage?", options:["A Cloud providers may have lower encryption standards than on-premises solutions","B Cloud providers have exclusive access to all stored customer data","C Cloud storage is more expensive than on-premises alternatives","D Data may cross jurisdictional boundaries affecting legal protection and compliance"], correct:3, explanation:"Cloud data may be stored across multiple geographies, each with different legal frameworks for data protection, surveillance, and law enforcement access. Organizations must understand where data resides and applicable legal obligations." },
  { id:30595, domain:2, level:2, question:"What is data remanence and why is it a security concern?", options:["A Data that remains accessible after authorized access is revoked","B Residual data remaining on storage media after deletion that may be recoverable","C Data that is transmitted but not received by the intended recipient","D Backup data that exceeds the defined retention period"], correct:1, explanation:"Data remanence is residual data remaining on storage media after deletion attempts. Standard deletion only removes file system references; data can be recovered with forensic tools. Secure deletion (overwriting) or physical destruction is required for sensitive data." },
  { id:30596, domain:2, level:2, question:"What does 'right to erasure' (right to be forgotten) under GDPR require?", options:["A Deleting all data in a system on request from any user","B Erasing personal data when there is no longer a legitimate basis for retaining it","C Allowing individuals to view and copy all data held about them","D Permanently deleting backups and archives on demand"], correct:1, explanation:"GDPR's right to erasure requires organizations to delete personal data when the individual withdraws consent, the purpose has been fulfilled, or retention is no longer justified, subject to exceptions for legal obligations and public interest." },
  { id:30597, domain:2, level:2, question:"What is the primary purpose of data loss prevention (DLP) classification?", options:["A Automatically encrypting all classified files in the organization","B Classifying data breaches by severity for incident response prioritization","C Preventing all data from leaving the organization's network","D Identifying sensitive data through content inspection so appropriate controls can be applied"], correct:3, explanation:"DLP classification identifies sensitive data (PII, financial records, intellectual property) through content inspection, enabling policies that prevent unauthorized exfiltration via email, USB, cloud upload, or other channels." },
  { id:30598, domain:2, level:2, question:"What is the concept of data sovereignty?", options:["A The requirement that data is subject to the laws of the country where it is stored or processed","B An organization's right to control all data within its network","C Data that is classified at the highest sensitivity level","D Government ownership of certain categories of national data"], correct:0, explanation:"Data sovereignty means data is subject to the laws and governance of the country where it resides. Organizations must ensure data stored in foreign jurisdictions complies with both local and home-country regulations." },
  { id:30599, domain:2, level:2, question:"What is the difference between data owners and data custodians?", options:["A Data owners have accountability for data; custodians implement the technical controls the owner defines","B Data owners control the data physically; custodians control it logically","C Data owners are business users; custodians are legal and compliance teams","D Data owners classify data; custodians access the data for business purposes"], correct:0, explanation:"Data owners (business stakeholders) decide classification and acceptable use. Data custodians (IT/security) implement and maintain the technical controls the owner requires—backup, access controls, encryption—without making policy decisions." },
  { id:30600, domain:2, level:2, question:"What is a data handling procedure?", options:["A A specific set of instructions for how to process, store, transmit, and dispose of data of a given classification","B A policy document defining acceptable use of organizational data","C A risk assessment methodology for evaluating data security risks","D A regulatory requirement document for specific data types"], correct:0, explanation:"Data handling procedures define step-by-step instructions for properly managing data at each classification level—how to store, transmit, access, label, and dispose of data according to its sensitivity, translating policy into operational practice." }
];
